const body = $input.first().json.body || $input.first().json;
const text = (body.text || body.message || '').trim();
const chatId = String(body.chatId || body.chat_id || '7713811206');

if (!text) {
  return [{ json: { error: true, message: 'text is required' } }];
}

const SPECIALISTS = [
  { id: 'executive', icon: '\u{1F9ED}', label: '\uCD1D\uAD04', keywords: ['\uC6B0\uC120\uC21C\uC704','\uBB50\uBD80\uD130','\uC815\uB9AC\uD574\uC918','\uB85C\uB4DC\uB9F5','\uD68C\uC758','\uD578\uB4DC\uC624\uD504','\uC804\uBB38 \uBE44\uC11C'], prompt: '\uB108\uB294 PRESSCO21\uC758 \uCD1D\uAD04 \uBE44\uC11C\uC774\uB2E4. \uB300\uD45C\uC758 \uC6B0\uC120\uC21C\uC704\uB97C \uC815\uB9AC\uD558\uACE0 \uD504\uB85C\uC81D\uD2B8 \uAC04 \uC870\uC728\uC744 \uB2F4\uB2F9\uD55C\uB2E4. "\uC0C1\uD669 \u2192 \uC6B0\uC120\uC21C\uC704 \u2192 \uB2E4\uC74C \uD589\uB3D9" \uD3EC\uB9F7\uC73C\uB85C \uAC04\uACB0\uD558\uAC8C \uB2F5\uD574\uB77C.' },
  { id: 'strategy', icon: '\u{1F3DB}', label: '\uD30C\uD2B8\uB108\uD074\uB798\uC2A4', keywords: ['\uD30C\uD2B8\uB108\uD074\uB798\uC2A4','\uD611\uD68C','\uAC15\uC0AC','\uD074\uB798\uC2A4','\uC218\uAC15\uC0DD','PRD','\uBE0C\uB79C\uB4DC'], prompt: '\uB108\uB294 PRESSCO21 \uD30C\uD2B8\uB108\uD074\uB798\uC2A4 \uC804\uB7B5\uAC00\uC774\uB2E4. \uAF43 \uACF5\uC608 \uAD50\uC721 \uD50C\uB7AB\uD3FC \uC804\uB7B5, \uAC15\uC0AC \uC6B4\uC601, \uD074\uB798\uC2A4 \uAE30\uD68D\uC744 \uB2F4\uB2F9\uD55C\uB2E4.' },
  { id: 'storefront', icon: '\u{1F6CD}', label: '\uC2A4\uD1A0\uC5B4', keywords: ['\uBA54\uC774\uD06C\uC0F5','\uC0C1\uC138\uD398\uC774\uC9C0','\uC7A5\uBC14\uAD6C\uB2C8','\uACB0\uC81C','\uCE74\uD14C\uACE0\uB9AC','\uC804\uD658\uC728','\uC2A4\uD1A0\uC5B4'], prompt: '\uB108\uB294 PRESSCO21 \uBA54\uC774\uD06C\uC0F5 \uC2A4\uD1A0\uC5B4\uD504\uB860\uD2B8 \uC804\uBB38\uAC00\uC774\uB2E4. UI/UX, \uC804\uD658\uC728 \uCD5C\uC801\uD654, \uC0C1\uC138\uD398\uC774\uC9C0 \uAC1C\uC120\uC744 \uB2F4\uB2F9\uD55C\uB2E4.' },
  { id: 'crm', icon: '\u{1F4D2}', label: 'CRM', keywords: ['CRM','\uBA85\uC138\uD45C','\uAC70\uB798\uBA85\uC138\uC11C','\uACAC\uC801\uC11C','\uC218\uAE08','\uC785\uAE08','\uACE0\uAC1D'], prompt: '\uB108\uB294 PRESSCO21 CRM \uC6B4\uC601\uC790\uC774\uB2E4. \uACE0\uAC1D \uAD00\uB9AC, \uC815\uC0B0, \uAC70\uB798\uBA85\uC138\uC11C, \uC785\uAE08 \uCC98\uB9AC\uB97C \uB2F4\uB2F9\uD55C\uB2E4.' },
  { id: 'automation', icon: '\u2699\uFE0F', label: '\uC790\uB3D9\uD654', keywords: ['n8n','\uC6CC\uD06C\uD50C\uB85C\uC6B0','\uC790\uB3D9\uD654','\uD15C\uB808\uADF8\uB7A8','\uBD07','API'], prompt: '\uB108\uB294 PRESSCO21 \uC790\uB3D9\uD654 \uC804\uBB38\uAC00\uC774\uB2E4. n8n \uC6CC\uD06C\uD50C\uB85C\uC6B0, \uD15C\uB808\uADF8\uB7A8 \uBD07, API \uC5F0\uB3D9\uC744 \uB2F4\uB2F9\uD55C\uB2E4.' },
  { id: 'knowledge', icon: '\u{1F4DA}', label: '\uC9C0\uC2DD', keywords: ['\uD68C\uC0AC','\uC7AC\uBB34','\uBE0C\uB79C\uB4DC','\uC815\uCC45','\uADDC\uC815','\uB9E4\uCD9C','\uB9C8\uC9C4'], prompt: '\uB108\uB294 PRESSCO21 \uD68C\uC0AC \uC9C0\uC2DD \uC804\uBB38\uAC00\uC774\uB2E4. \uD68C\uC0AC \uC804\uB7B5, \uC7AC\uBB34, \uBE0C\uB79C\uB4DC \uC815\uCC45\uC744 \uB2F4\uB2F9\uD55C\uB2E4.' }
];

const lower = text.toLowerCase();
let matched = SPECIALISTS[0];
let maxScore = 0;

for (const s of SPECIALISTS) {
  let score = 0;
  for (const kw of s.keywords) {
    if (lower.includes(kw.toLowerCase())) score += 1;
  }
  if (score > maxScore) {
    maxScore = score;
    matched = s;
  }
}

const isComplex = text.length > 200 || lower.includes('\uBD84\uC11D') || lower.includes('\uC804\uB7B5') || lower.includes('\uAE30\uD68D\uC548') || lower.includes('\uD300\uBBF8\uD305');

return [{ json: {
  error: false,
  specialist: matched.id,
  icon: matched.icon,
  label: matched.label,
  systemPrompt: matched.prompt,
  userMessage: text,
  chatId,
  isComplex: isComplex ? 1 : 0,
  score: maxScore
} }];

