const classify = $('Specialist 분류').first().json;
const gemini = $input.first().json;

let answer = '';
try {
  answer = gemini.candidates[0].content.parts[0].text || '';
} catch(e) {
  answer = 'AI 응답 파싱 실패: ' + JSON.stringify(gemini).slice(0, 200);
}

const msg = `${classify.icon} <b>[${classify.label}]</b>\n\n${answer.replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]))}\n\n\u{1F4CD} \uC11C\uBC84 (Gemini) | \uC804\uBB38: ${classify.label}`;

return [{ json: { message: msg, chatId: classify.chatId, specialist: classify.specialist } }];
